package org.jsoup.parser;

import org.jsoup.helper.Validate;
import org.jsoup.nodes.Attributes;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;

import java.util.ArrayList;

/**
 * @author Jonathan Hedley
 */
abstract class TreeBuilder {
    CharacterReader reader;
    Tokeniser tokeniser;
    protected Document doc; // current doc we are building into
    protected ArrayList<Element> stack; // the stack of open elements
    protected String baseUri; // current base uri, for creating new elements
    protected Token currentToken; // currentToken is used only for error tracking.
    protected ParseErrorList errors; // null when not tracking errors

    private Token.StartTag start = new Token.StartTag(); // start tag to process
    private Token.EndTag end  = new Token.EndTag();

    protected void initialiseParse(String input, String baseUri, ParseErrorList errors) {
        Validate.notNull(input, "String input must not be null");
        Validate.notNull(baseUri, "BaseURI must not be null");

        doc = new Document(baseUri);
        reader = new CharacterReader(input);
        this.errors = errors;
        tokeniser = new Tokeniser(reader, errors);
        stack = new ArrayList<Element>(32);
        this.baseUri = baseUri;
    }

    Document parse(String input, String baseUri) {
        return parse(input, baseUri, ParseErrorList.noTracking());
    }

    Document parse(String input, String baseUri, ParseErrorList errors) {
        initialiseParse(input, baseUri, errors);
        runParser();
        return doc;
    }

    protected void runParser() {
        while (true) {
            Token token = tokeniser.read();
            process(token);
            token.reset();

            if (token.type == Token.TokenType.EOF)
                break;
        }
    }

    protected abstract boolean process(Token token);

    protected boolean processStartTag(String name) {
        return process(start.reset().name(name));
    }

    public boolean processStartTag(String name, Attributes attrs) {
        start.reset();
        start.nameAttr(name, attrs);
        return process(start);
    }

    protected boolean processEndTag(String name) {
        return process(end.reset().name(name));
    }


    protected Element currentElement() {
        int size = stack.size();
        return size > 0 ? stack.get(size-1) : null;
    }
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.*;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;

import static org.junit.Assert.*;

public class StepDefs {
    private String inputHtml;
    private Document document;
    private String renderedOutput;

    @Given("the input HTML:")
    public void the_input_html(String html) {
        this.inputHtml = html.trim();
    }

    @When("the HTML is parsed")
    public void the_html_is_parsed() {
        try {
            this.document = Jsoup.parse(inputHtml);
            this.renderedOutput = document.html();
        } catch (Exception e) {
            // Capture any parsing errors if needed
            throw new RuntimeException("Error parsing HTML", e);
        }
    }

    @Then("the text {string} should appear after the comment {string} in the rendered output")
    public void the_text_should_appear_after_the_comment_in_the_rendered_output(String text, String comment) {
        // Check if the text appears after the comment in the rendered output
        int commentPos = renderedOutput.indexOf("<!--" + comment);
        int textPos = renderedOutput.indexOf(text);

        assertTrue("Comment '" + comment + "' should be found in the output", commentPos != -1);
        assertTrue("Text '" + text + "' should be found in the output", textPos != -1);
        assertTrue("Text '" + text + "' should appear after comment '" + comment + "'", textPos > commentPos);
    }

    @And("the structure should reflect that the paragraph is fostered out of the inner table but remains after the preceding table content")
    public void the_structure_should_reflect_that_the_paragraph_is_fostered_out_of_the_inner_table_but_remains_after_the_preceding_table_content() {
        // Check if the paragraph element exists in the document
        Elements pElements = document.select("p");
        assertEquals("Should have exactly one paragraph", 1, pElements.size());

        // The p element should exist in the structure and be outside the deeply nested table
        String paragraphText = pElements.first().text();
        assertEquals("Why am I here?", paragraphText);

        // Check the overall document structure
        // There should be a nested table structure
        Elements tables = document.select("table");
        assertEquals("Should have multiple tables", 3, tables.size());

        // The paragraph should not be nested within the innermost table
        Element innermostTable = tables.get(2); // The <table><p>Why am I here?</p></table>
        Elements innermostP = innermostTable.select("p");

        // In the buggy version, the p might be inside the innermost table
        // In the fixed version, the p might be fostered out to a parent context
        // The requirement is that the order is preserved - text should appear after comment
    }
}

