    if (isLastTableParent) {
        Validate.notNull(lastTable); // last table cannot be null by this point.

        // Use insertion position context to maintain proper order
        Node insertionPoint = getInsertionPosition();
        if (insertionPoint != null && insertionPoint.parent() != null && 
            insertionPoint.parent() == fosterParent && insertionPoint != lastTable) {
            // Insert after the tracked insertion point to maintain document order
            insertionPoint.after(in);
        } else {
            // Default behavior: insert before the table
            lastTable.before(in);
        }
    } else {
        fosterParent.appendChild(in);
    }

    // Clear the insertion position after using it to avoid stale context
    setInsertionPosition(null);
}

